const getPatientVisitMetaByDate = `-- name: GetPatientVisitMetaByDate :many
SELECT DISTINCT ON (a.id)
  a.id,
  a.vid,
  p.family_group,
  a.reg_date,
  a.queue_no,
  p.name,
  p.khmer_name,
  p.gender,
  p.village,
  p.contact_no,
  p.drug_allergies,
  a.sent_to_id,
  dc.referral_needed,
  EXISTS (
    SELECT 1
    FROM prescriptions pr
    JOIN prescription_lines pl ON pl.prescription_id = pr.id
    WHERE pr.patient_id = a.id
      AND pr.vid = a.vid
  ) AS has_prescription_with_drug,
  CASE
    WHEN EXISTS (
      SELECT 1
      FROM prescriptions pr
      JOIN prescription_lines pl ON pl.prescription_id = pr.id
      WHERE pr.patient_id = a.id
        AND pr.vid = a.vid
    ) THEN NOT EXISTS (
      SELECT 1
      FROM prescriptions pr
      JOIN prescription_lines pl ON pl.prescription_id = pr.id
      WHERE pr.patient_id = a.id
        AND pr.vid = a.vid
        AND (pl.is_packed IS NOT TRUE)
    )
    ELSE FALSE
  END AS all_prescription_drugs_packed,
  EXISTS (
    SELECT 1
    FROM prescriptions pr
    WHERE pr.patient_id = a.id
      AND pr.vid = a.vid
      AND pr.is_dispensed = TRUE
  ) AS prescription_dispensed
FROM admin a
JOIN patient_details p ON p.id = a.id
LEFT JOIN doctors_consultation dc
  ON a.id = dc.id AND a.vid = dc.vid
WHERE a.reg_date = $1
ORDER BY a.id, a.vid DESC
`

