const listAdminVisits = `-- name: ListAdminVisits :many
SELECT vid, reg_date
FROM admin
WHERE id = $1
ORDER BY vid
`

type ListAdminVisitsRow struct {
	Vid     int32     `json:"vid"`
	RegDate time.Time `json:"reg_date"`
}

func (q *Queries) ListAdminVisits(ctx context.Context, id int32) ([]ListAdminVisitsRow, error) {
	rows, err := q.db.Query(ctx, listAdminVisits, id)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListAdminVisitsRow
	for rows.Next() {
		var i ListAdminVisitsRow
		if err := rows.Scan(&i.Vid, &i.RegDate); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

